import React, { useState } from 'react';

const ContactForm: React.FC = () => {
  const [isSending, setIsSending] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    category: '선택해 주세요',
    content: '',
    privacy: false
  });

  const WEBHOOK_URL = "https://lawahn79.app.n8n.cloud/webhook/3d332dc2-1f72-412c-82d5-5a7ff029dc10"; 

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target as HTMLInputElement;
    const val = type === 'checkbox' ? (e.target as HTMLInputElement).checked : value;
    setFormData(prev => ({ ...prev, [name]: val }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.name.trim()) return alert('성함을 입력해 주세요.');
    if (!formData.phone.trim()) return alert('연락처를 입력해 주세요.');
    if (formData.category === '선택해 주세요') return alert('상담 분야를 선택해 주세요.');
    if (!formData.content.trim()) return alert('문의 내용을 입력해 주세요.');
    if (!formData.privacy) return alert('개인정보 수집 및 이용에 동의해 주세요.');

    setIsSending(true);

    try {
      const response = await fetch(WEBHOOK_URL, {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json' 
        },
        mode: 'cors', // CORS 모드 명시
        body: JSON.stringify({
          formType: 'BottomContactForm',
          timestamp: new Date().toISOString(),
          ...formData
        })
      });

      if (response.ok) {
        setSubmitted(true);
      } else {
        const errorText = await response.text();
        console.error("서버 응답 오류:", errorText);
        alert(`전송 중 오류가 발생했습니다 (상태 코드: ${response.status}). n8n 서버의 CORS 설정을 확인해 주세요.`);
      }
    } catch (error) {
      console.error('Fetch 에러:', error);
      alert('네트워크 연결 문제 또는 CORS 정책으로 인해 전송에 실패했습니다. n8n 설정에서 해당 도메인의 접근 허용이 필요합니다.');
    } finally {
      setIsSending(false);
    }
  };

  if (submitted) {
    return (
      <section id="consultation-form" className="py-24 bg-white scroll-mt-24">
        <div className="container mx-auto px-6 text-center">
          <div className="max-w-xl mx-auto p-12 bg-slate-50 rounded-3xl border border-amber-100 shadow-xl animate-in zoom-in-95 duration-500">
            <div className="text-6xl mb-6">✉️</div>
            <h2 className="text-3xl font-black text-slate-900 mb-4">상담 예약이 접수되었습니다</h2>
            <p className="text-slate-600 mb-8 leading-relaxed">
              안재현 변호사가 내용을 검토한 후 <br />
              <span className="text-amber-600 font-bold">빠른 시간 내에</span> 직접 연락드리겠습니다.
            </p>
            <button 
              onClick={() => {
                setSubmitted(false);
                setFormData({ name: '', phone: '', category: '선택해 주세요', content: '', privacy: false });
              }}
              className="px-10 py-4 bg-blue-900 text-white font-black rounded-2xl hover:bg-blue-800 transition-all shadow-lg"
            >
              다시 작성하기
            </button>
          </div>
        </div>
      </section>
    );
  }

  return (
    <section id="consultation-form" className="py-24 bg-slate-50 scroll-mt-24">
      <div className="container mx-auto px-6">
        <div className="max-w-5xl mx-auto">
          <div className="text-center mb-16">
            <div className="text-amber-600 font-bold mb-4 tracking-[0.2em] uppercase text-xs">Direct Consultation</div>
            <h2 className="text-4xl md:text-5xl font-black text-slate-900 mb-6 tracking-tighter">
              무료 법률상담 예약
            </h2>
            <p className="text-slate-500 text-lg">
              사건의 핵심을 찌르는 명쾌한 해답, 법률사무소 '安'이 함께합니다.
            </p>
          </div>

          <div className="bg-white p-8 md:p-16 rounded-[3rem] shadow-[0_30px_60px_-15px_rgba(0,0,0,0.08)] border border-slate-100 relative">
            {isSending && (
              <div className="absolute inset-0 bg-white/80 backdrop-blur-[2px] z-10 flex flex-col items-center justify-center rounded-[3rem]">
                <div className="w-12 h-12 border-4 border-amber-500 border-t-transparent rounded-full animate-spin mb-4"></div>
                <p className="text-blue-900 font-black">보안 서버로 데이터를 전송 중입니다...</p>
              </div>
            )}

            <form onSubmit={handleSubmit}>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-x-10 gap-y-8 mb-10">
                <div className="space-y-2">
                  <label className="text-sm font-black text-slate-800 ml-1">의뢰인 성함</label>
                  <input 
                    name="name"
                    type="text" 
                    value={formData.name}
                    onChange={handleChange}
                    placeholder="성함을 입력하세요"
                    className="w-full px-6 py-5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-amber-500 focus:bg-white outline-none transition-all"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-black text-slate-800 ml-1">연락처</label>
                  <input 
                    name="phone"
                    type="tel" 
                    value={formData.phone}
                    onChange={handleChange}
                    placeholder="010-0000-0000"
                    className="w-full px-6 py-5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-amber-500 focus:bg-white outline-none transition-all"
                  />
                </div>
              </div>

              <div className="mb-10 space-y-2">
                <label className="text-sm font-black text-slate-800 ml-1">상담 분야</label>
                <div className="relative">
                  <select 
                    name="category"
                    value={formData.category}
                    onChange={handleChange}
                    className="w-full px-6 py-5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-amber-500 focus:bg-white outline-none transition-all appearance-none cursor-pointer"
                  >
                    <option disabled>선택해 주세요</option>
                    <option>성범죄/마약</option>
                    <option>이혼/가사/상속</option>
                    <option>민사/부동산</option>
                    <option>형사/경제범죄</option>
                    <option>기타 법률 상담</option>
                  </select>
                  <div className="absolute right-6 top-1/2 -translate-y-1/2 pointer-events-none">
                    <svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
                  </div>
                </div>
              </div>

              <div className="mb-10 space-y-2">
                <label className="text-sm font-black text-slate-800 ml-1">상담 내용</label>
                <textarea 
                  name="content"
                  rows={5}
                  value={formData.content}
                  onChange={handleChange}
                  placeholder="상담을 원하시는 내용을 간략하게 적어주시면 더 정확한 상담이 가능합니다."
                  className="w-full px-6 py-5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-amber-500 focus:bg-white outline-none transition-all resize-none"
                ></textarea>
              </div>

              <div className="flex items-center gap-3 mb-12 ml-1">
                <input 
                  type="checkbox" 
                  id="privacy" 
                  name="privacy"
                  checked={formData.privacy}
                  onChange={handleChange}
                  className="w-6 h-6 accent-amber-600 rounded cursor-pointer" 
                />
                <label htmlFor="privacy" className="text-sm text-slate-500 cursor-pointer select-none font-bold">
                  개인정보 수집 및 이용에 동의합니다. (작성하신 내용은 변호사 외에 절대 공개되지 않습니다.)
                </label>
              </div>

              <button 
                type="submit"
                disabled={isSending}
                className="w-full py-6 bg-slate-900 text-white font-black text-xl rounded-2xl shadow-2xl hover:bg-amber-600 transition-all duration-300 disabled:bg-slate-400"
              >
                {isSending ? '상담 신청 처리 중...' : '무료 법률상담 신청하기'}
              </button>
            </form>
          </div>
        </div>
      </div>
    </section>
  );
};

export default ContactForm;

import React, { useState, useEffect } from 'react';

interface ConsultationPopupProps {
  onClose: () => void;
}

const ConsultationPopup: React.FC<ConsultationPopupProps> = ({ onClose }) => {
  const [isVisible, setIsVisible] = useState(false);
  const [isSending, setIsSending] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    content: ''
  });

  const WEBHOOK_URL = "https://lawahn79.app.n8n.cloud/webhook/3d332dc2-1f72-412c-82d5-5a7ff029dc10"; 

  useEffect(() => {
    const timer = setTimeout(() => setIsVisible(true), 800);
    return () => clearTimeout(timer);
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.name.trim()) return alert('성함을 입력해 주세요.');
    if (!formData.phone.trim()) return alert('연락처를 입력해 주세요.');

    setIsSending(true);

    try {
      const response = await fetch(WEBHOOK_URL, {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json' 
        },
        mode: 'cors', // CORS 모드 명시
        body: JSON.stringify({
          formType: 'PopupConsultationForm',
          timestamp: new Date().toISOString(),
          ...formData
        })
      });

      if (response.ok) {
        alert('상담 신청이 접수되었습니다!');
        onClose();
      } else {
        const errorText = await response.text();
        console.error("서버 응답 오류:", errorText);
        alert(`전송 중 오류가 발생했습니다 (${response.status}).`);
      }
    } catch (error) {
      console.error('Fetch 에러:', error);
      alert('네트워크 연결 문제 또는 CORS 보안 정책으로 인해 전송에 실패했습니다.');
    } finally {
      setIsSending(false);
    }
  };

  if (!isVisible) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md animate-in fade-in duration-500">
      <div className="bg-white w-full max-w-4xl max-h-[90vh] md:max-h-[85vh] rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col md:flex-row relative animate-in slide-in-from-bottom-8 duration-700">

        {isSending && (
          <div className="absolute inset-0 bg-white/70 backdrop-blur-sm z-[110] flex flex-col items-center justify-center p-6 text-center">
            <div className="w-12 h-12 border-4 border-amber-500 border-t-transparent rounded-full animate-spin mb-4"></div>
            <p className="text-blue-900 font-black">상담 내용을 안전하게 전송 중입니다...</p>
          </div>
        )}

        <button 
          onClick={onClose}
          className="absolute top-6 right-6 z-[120] p-2 hover:bg-slate-100 rounded-full text-slate-400 hover:text-slate-900 transition-all"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" />
          </svg>
        </button>

        <div className="w-full h-full flex flex-col md:flex-row overflow-y-auto">
          <div className="md:w-5/12 bg-slate-900 p-10 text-white flex flex-col justify-between relative shrink-0">
            <div className="absolute top-0 right-0 w-48 h-48 bg-amber-500/10 rounded-full blur-[60px] -translate-y-1/2 translate-x-1/2"></div>

            <div className="relative z-10">
              <div className="flex items-center gap-3 mb-8">
                <div className="text-amber-500 font-serif text-5xl leading-none">安</div>
                <div className="text-white text-lg font-black tracking-tight">법률사무소 '安'</div>
              </div>

              <h3 className="text-3xl font-black mb-6 leading-tight">
                당신의 평안을 위한<br />
                <span className="text-amber-500">24시 무료상담</span>
              </h3>

              <ul className="space-y-4">
                {['형사/성범죄 전문', '이혼/재산분할 전문', '변호사 직접 상담'].map((text, i) => (
                  <li key={i} className="flex items-center gap-3 text-sm font-bold text-slate-300">
