대략 이소스코드를 참고해서 폼전송을 구현해봐 참고만해 폼 관련된소스코드를
<!-- ▼▼▼ 여기서부터 복사해서 </body> 태그 바로 위에 붙여넣으세요 ▼▼▼ -->
<script>
    // ============================================================
    // [설정] 아래 1번, 2번만 본인 것에 맞게 수정하세요.
    // ============================================================
    const CONFIG = {
        // 1. 아까 복사한 '구글 웹 앱 URL'을 따옴표 안에 넣으세요.
        scriptUrl: "https://script.google.com/macros/s/AKfycbwpAeaJLVzSkzrAaHoJYQyXMd0PCKtw_oHvo-2YAhSxEvHqenTR90rwz6R6egp4pawS4Q/exec",

        // 2. 홈페이지에 있는 입력칸들의 ID를 적어주세요.
        // (따옴표 안의 값을 내 홈페이지 소스코드의 id와 똑같이 맞춰야 합니다)
        domIds: {
            form:    "consultForm",    // 폼(Form) 태그 ID
            name:    "name",           // 이름 입력창 ID
            phone:   "phone",          // 연락처 입력창 ID
            email:   "email",          // 이메일 입력창 ID (없으면 "")
            message: "message",        // 내용 입력창 ID
            button:  "submitBtn"       // 전송 버튼 ID
        }
    };
    // ============================================================

    document.addEventListener("DOMContentLoaded", function() {
        const form = document.getElementById(CONFIG.domIds.form);
        const btn = document.getElementById(CONFIG.domIds.button);

        if (form) {
            form.addEventListener("submit", function(e) {
                e.preventDefault(); // 화면 새로고침 방지

                // URL 입력 확인
                if (!CONFIG.scriptUrl || CONFIG.scriptUrl.includes("아이디")) {
                    alert("스크립트 코드에서 'scriptUrl' 부분에 구글 주소를 넣어주세요!");
                    return;
                }

                // 버튼 로딩 처리
                const originalBtnText = btn ? btn.innerText : "전송";
                if (btn) {
                    btn.disabled = true;
                    btn.innerText = "전송 중...";
                }

                // 데이터 가져오기
                const formData = {
                    name: document.getElementById(CONFIG.domIds.name)?.value || "",
                    phone: document.getElementById(CONFIG.domIds.phone)?.value || "",
                    email: CONFIG.domIds.email ? (document.getElementById(CONFIG.domIds.email)?.value || "") : "",
                    message: document.getElementById(CONFIG.domIds.message)?.value || ""
                };

                // 구글로 전송 (텔레그램 알림 발송됨)
                fetch(CONFIG.scriptUrl, {
                    method: "POST",
                    mode: "no-cors",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify(formData)
                })
                .then(() => {
                    alert("✅ 상담 신청이 완료되었습니다.");
                    form.reset();
                })
                .catch(error => {
                    console.error("Error:", error);
                    alert("❌ 전송 실패. 관리자에게 문의하세요.");
                })
                .finally(() => {
                    if (btn) {
                        btn.disabled = false;
                        btn.innerText = originalBtnText;
                    }
                });
            });
        }
    });
</script>
<!-- ▲▲▲ 여기까지 복사하세요 ▲▲▲ -->

